// // This module is designed to implement a 4-bit synchronous counter with a loadable initial value.
// It has a clock input (clk), a load input (load), a 4-bit data input (d), and a 4-bit data output (count).

module sync_counter_with_load (
    input clk,
    input load,
    input [3:0] d,
    output reg [3:0] count
);

    always @(posedge clk) begin
        if (!load) begin
            count <= d;
        end else begin
            count <= count - 1;
        end
    end

endmodule
